SELECT COUNT(1)
FROM activities

  AND type = #{type}
  AND status = #{status}
  AND status NOT IN ('UnderReview','FailReview','ActivityEnded')
  AND functionary = #{functionary}
  AND name LIKE CONCAT('%', #{name}, '%')
  AND start_time >= #{startFrom}
  AND start_time <= #{startTo}
  AND is_full = #{isFull}

SELECT id, functionary, name, type, description,
       enrollment_start_time, enrollment_end_time,
       start_time, expected_end_time, end_time, cover_path, max_participants, status, is_full, duration,
       rejected_reason, imported
FROM activities

  AND type = #{type}
  AND status = #{status}
  AND status NOT IN ('UnderReview','FailReview','ActivityEnded')
  AND functionary = #{functionary}
  AND name LIKE CONCAT('%', #{name}, '%')
  AND start_time >= #{startFrom}
  AND start_time <= #{startTo}
  AND is_full = #{isFull}

ORDER BY start_time DESC
LIMIT #{pageSize} OFFSET #{offset}

